import{_ as e,o as i,c as t,a3 as s}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Web.Gateway","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/web-gateway.md","filePath":"cosmos/framework/packages/web-gateway.md","lastUpdated":1783216089000}'),r={name:"cosmos/framework/packages/web-gateway.md"};function o(d,a,n,l,h,c){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="xihan-framework-web-gateway" tabindex="-1">XiHan.Framework.Web.Gateway <a class="header-anchor" href="#xihan-framework-web-gateway" aria-label="Permalink to &quot;XiHan.Framework.Web.Gateway&quot;">​</a></h1><blockquote><p>API 网关：作为流量入口做灰度路由决策、请求追踪与网关级异常处理；限流/熔断可按配置开关。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Web.Gateway</code></li><li><strong>模块类</strong>：<code>XiHanWebGatewayModule</code></li><li><strong>所在层</strong>：Web 层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Web.Gateway 是放在流量入口的一层薄治理组件。它的职责是「路由决策 + 策略执行」——为进入的请求构建灰度上下文、调用灰度规则引擎做决策，并把结果注入 <code>HttpContext</code>，供后续中间件按决策转发；同时提供网关级异常处理与请求追踪。真正的灰度规则引擎（<code>IGrayRuleEngine</code>）与负载均衡等能力沉淀在 <a href="./traffic">Traffic</a> 模块，本包是它在 Web 管道中的接入层。</p><p>注意：本包本身不负责业务逻辑，也不管理规则本身，只在请求管道里执行决策。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要在入口做<strong>灰度发布 / 灰度路由</strong>：按租户、规则把请求分流到不同版本或分组。</li><li>需要网关级的统一异常响应与请求追踪。</li><li>需要在流量入口集中控制超时、CORS 来源、全局 Header 等入口策略。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Web.Gateway</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanWebGatewayModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 中调用 <code>AddGrayRouting()</code>（由 Traffic 模块提供）注册灰度路由服务；网关中间件通过 <code>UseGateway()</code> 挂入应用管道。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>灰度路由决策</strong>：<code>GrayRoutingMiddleware</code> 构建灰度上下文、经 <code>IGrayRuleEngine</code> 决策，并把结果注入 <code>HttpContext</code>（不负责实际转发）。</li><li><strong>请求追踪</strong>：<code>RequestTracingMiddleware</code> 为网关请求打追踪信息。</li><li><strong>网关异常处理</strong>：<code>GatewayExceptionMiddleware</code> 置于最外层，统一网关级错误响应（<code>GatewayErrorResponse</code>）。</li><li><strong>入口策略配置</strong>：<code>XiHanGatewayOptions</code>（配置节 <code>XiHan:Web:Gateway</code>）开关灰度路由、请求追踪、限流、熔断，并配置请求超时、CORS 来源与全局 Header。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanWebGatewayModule</code></td><td>模块类，注册灰度路由服务</td></tr><tr><td><code>GrayRoutingMiddleware</code></td><td>灰度路由决策中间件</td></tr><tr><td><code>RequestTracingMiddleware</code></td><td>请求追踪中间件</td></tr><tr><td><code>GatewayExceptionMiddleware</code></td><td>网关级异常处理中间件</td></tr><tr><td><code>XiHanGatewayOptions</code></td><td>网关配置（灰度/追踪/限流/熔断/超时/CORS/全局 Header）</td></tr><tr><td><code>UseGateway()</code> / <code>UseGrayRouting()</code> / <code>UseRequestTracing()</code></td><td>应用构建器扩展，挂载网关中间件</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：<a href="./web-core">XiHan.Framework.Web.Core</a>、<a href="./traffic">XiHan.Framework.Traffic</a>（灰度规则引擎的真源）、<a href="./authorization">XiHan.Framework.Authorization</a>、<a href="./multitenancy">XiHan.Framework.MultiTenancy</a>、<a href="./logging">XiHan.Framework.Logging</a>、<a href="./serialization">XiHan.Framework.Serialization</a>。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./traffic">XiHan.Framework.Traffic</a> — 灰度路由规则引擎与流量治理能力的实现层。</li><li><a href="./web-api">XiHan.Framework.Web.Api</a> — 应用侧的限流与熔断中间件（网关与业务服务可各自启用）。</li></ul>`,21)])])}const g=e(r,[["render",o]]);export{k as __pageData,g as default};
